fn process_user(input: &str) -> Result<User, Error> {
    let Some(id) = input.parse::<u64>().ok() else {
        return Err(Error::InvalidId);
    };
    let Some(user) = find_user(id) else {
        return Err(Error::NotFound);
    };
    // happy path continues flat
    Ok(user)
}

