Code Good:
struct Server {
    host: String,
    port: u16,
}

impl Server {
    fn new(host: impl Into<String>, port: u16) -> Self {
        Self { host: host.into(), port }
    }

    fn with_default_port(host: impl Into<String>) -> Self {
        Self::new(host, 8080)
    }

    fn from_env() -> Result<Self, std::env::VarError> {
        let host = std::env::var("HOST")?;
        let port = std::env::var("PORT")?.parse().unwrap_or(8080);
        Ok(Self { host, port })
    }
}

