enum Command {
    Start,
    Stop,
    Restart,
    Status,
}

fn handle(cmd: Command) {
    match cmd {
        Command::Start => start(),
        Command::Stop => stop(),
        Command::Restart => { stop(); start(); }
        Command::Status => print_status(),
    }
    // adding a new variant produces a compile error here
}

